--QUERY 10select *, '25%' as porcentaje_aumento, (costo + cast((costo * 0.25) as decimal(7,3))) as NuevoCostofrom Asignaturaswhere area = (				select areaid				from area				where nombre like '%Marketing%'			)and Jornada = 'Manana'--QUERY 9select nombre, apellido, documentofrom staffwhere Asignatura in (						select AsignaturasID						from Asignaturas						where nombre like '%UX%'					);--QUERY 8select Documento, Domicilio, [codigo postal], Nombre, Apellido, [fecha ingreso]from estudianteswhere [fecha ingreso] = (						select min([fecha ingreso])						from Estudiantes						)--QUERY 7select nombre, apellido, correo, camada, [fecha ingreso]from staffwhere correo like '%.edu'and DocentesID >= 100;--QUERY 6select nombre, apellido, DATEDIFF(year, [fecha de nacimiento], GETDATE()) as edadfrom estudianteswhere DATEDIFF(year, [fecha de nacimiento], GETDATE()) >= 18order by edad asc--QUERY 5select tipo, jornada, CAST(AVG(costo) as decimal (10,2)) promediofrom Asignaturasgroup by tipo, jornadaorder by promedio desc--QUERY 4select replace(tipo, 'Encargado ', '') as NuevoTipo, count(*) CantEncargadosfrom Encargadogroup by tipo;--QUERY 3select upper(CONCAT(nombre, '-', Apellido))from staffwhere year([fecha ingreso]) = 2021--QUERY 2select nombre, documento, telefonofrom Estudianteswhere profesion = (					select profesionesID					from profesiones					where Profesiones like '%gronom%'					)and [fecha de nacimiento] BETWEEN '1970-01-01' and '2000-12-31'